#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {
    double seek_time_ms;      // Time for head movement (ms)
    double rotational_latency_ms; // Average rotational latency (ms)
    double transfer_rate_mbps;   // Transfer rate (MB/s)
    int rpm;                    // Revolutions per minute
} DiskParams;

double calculate_rotational_latency(int rpm) {
    // Average rotational latency = 1/2 × time for one rotation
    double time_per_rotation = 60000.0 / rpm;  // ms per rotation
    return time_per_rotation / 2.0;
}

double calculate_total_access_time(DiskParams disk, int num_sectors, int sector_size) {
    double latency = calculate_rotational_latency(disk.rpm);
    double transfer_time = (num_sectors * sector_size) / (disk.transfer_rate_mbps * 125000.0);

    return disk.seek_time_ms + latency + transfer_time;
}

int main() {
    DiskParams disk;
    int num_sectors = 10000;
    int sector_size = 512;

    disk.seek_time_ms = 8.0;
    disk.rpm = 7200;
    disk.transfer_rate_mbps = 50.0;

    double latency = calculate_rotational_latency(disk.rpm);
    double total_time = calculate_total_access_time(disk, num_sectors, sector_size);
    double transfer_time = (num_sectors * sector_size) / (disk.transfer_rate_mbps * 125000.0);

    printf("=== Disk Access Time Calculation ===\n");
    printf("Seek Time: %.2f ms\n", disk.seek_time_ms);
    printf("Rotational Latency (avg): %.2f ms\n", latency);
    printf("Transfer Time: %.2f ms\n", transfer_time);
    printf("Total Access Time: %.2f ms\n", total_time);

    return 0;
}
